// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section class=\"step\" id=\"s1\">\n<div class=\"step-header\">\n<div class=\"step-badge\">01</div>\n<h2>Prerequisites</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail sits on top of Django and adds image processing dependencies. Confirming versions now prevents confusing Pillow/libjpeg errors mid-build.</div>\n<div class=\"step-body\">\n<p>You need Python 3.10+ and a working C toolchain for image libraries (Pillow ships pre-built wheels for most platforms, so this is usually automatic). Check your version:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python3 --version\npip3 --version</pre>\n</div>\n<div>On Windows use <code>python</code> and <code>pip</code>. On macOS/Linux use <code>python3</code> and <code>pip3</code>. If <code>pip install Pillow</code> ever fails to find <code>libjpeg</code>, install it via your OS package manager first (<code>brew install jpeg</code> or <code>apt install libjpeg-dev</code>).</div>\n</section>\n<section class=\"step\" id=\"s2\">\n<div class=\"step-header\">\n<div class=\"step-badge\">02</div>\n<h2>Create a virtual environment</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>An isolated environment keeps Wagtail's dependency tree (Django, Pillow, Willow, django-taggit) from colliding with anything else on your machine.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>mkdir nebulablog &amp;&amp; cd nebulablog\npython3 -m venv venv\nsource venv/bin/activate <span># macOS / Linux</span>\n# venv\\Scripts\\activate <span># Windows PowerShell</span></pre>\n</div>\n<div>Your prompt will show <code>(venv)</code> once active. Everything you <code>pip install</code> from here on stays scoped to this folder.</div>\n</section>\n<section class=\"step\" id=\"s3\">\n<div class=\"step-header\">\n<div class=\"step-badge\">03</div>\n<h2>Install Wagtail</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Installing the <code>wagtail</code> package pulls in Django itself plus every required dependency -- you don't install Django separately.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install wagtail\npip freeze &gt; requirements.txt <span># lock versions immediately</span>\nwagtail --version <span># should print 6.x</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Wagtail tracks Django's release cycle closely. Check the <a href=\"https://docs.wagtail.org/en/stable/releases/upgrading.html\">compatibility table</a> before pinning specific versions of each in production.</div>\n</section>\n<section class=\"step\" id=\"s4\">\n<div class=\"step-header\">\n<div class=\"step-badge\">04</div>\n<h2>Generate the project</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The <code>wagtail start</code> command is a project template generator -- it scaffolds a <code>home</code> app, a <code>search</code> app, and sensible default settings already wired for Wagtail, saving you from assembling that boilerplate by hand.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">inside nebulablog/</span>\n</div>\n<pre>wagtail start core . <span># the dot keeps files in the current dir</span>\npip install -r requirements.txt <span># installs deps the template added</span>\npython manage.py startapp blog <span># your blog app -- created manually</span></pre>\n</div>\n<div>Unlike plain Django, the project name (<code>core</code>) is mostly cosmetic here -- Wagtail's real content lives in apps like <code>home</code> and the <code>blog</code> app you just created. <code>core/settings/</code> is already split into <code>base.py</code>, <code>dev.py</code>, and <code>production.py</code> for you.</div>\n</section>\n<section class=\"step\" id=\"s5\">\n<div class=\"step-header\">\n<div class=\"step-badge\">05</div>\n<h2>Understand the project structure</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail's generated layout differs from a bare Django project in two key ways: settings are pre-split, and a <code>home</code> app exists for your site's root page.</div>\n<div class=\"tree\">\n<span>nebulablog/</span>\n\u251c\u2500\u2500 <span>core/</span> <span># project package</span>\n\u2502 \u251c\u2500\u2500 <span>settings/</span>\n\u2502 \u2502 \u251c\u2500\u2500 <span>base.py</span> <span># shared settings</span>\n\u2502 \u2502 \u251c\u2500\u2500 <span>dev.py</span> <span># local dev overrides</span>\n\u2502 \u2502 \u2514\u2500\u2500 <span>production.py</span>\n\u2502 \u251c\u2500\u2500 <span>urls.py</span>\n\u2502 \u2514\u2500\u2500 <span>wsgi.py</span>\n\u251c\u2500\u2500 <span>home/</span> <span># root page app (generated)</span>\n\u2502 \u251c\u2500\u2500 <span>models.py</span> <span># HomePage model lives here</span>\n\u2502 \u2514\u2500\u2500 <span>templates/</span>\n\u251c\u2500\u2500 <span>search/</span> <span># built-in search view (generated)</span>\n\u251c\u2500\u2500 <span>blog/</span> <span># your app -- create models here</span>\n\u2502 \u251c\u2500\u2500 <span>models.py</span>\n\u2502 \u2514\u2500\u2500 <span>templates/blog/</span>\n\u251c\u2500\u2500 <span>static/</span> <span># your CSS / JS / images source</span>\n\u251c\u2500\u2500 <span>templates/</span> <span># base.html lives here</span>\n\u251c\u2500\u2500 <span>media/</span> <span># user-uploaded images (never commit)</span>\n\u251c\u2500\u2500 <span>venv/</span> <span># virtual env (never commit)</span>\n\u251c\u2500\u2500 <span>manage.py</span>\n\u2514\u2500\u2500 <span>requirements.txt</span>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Treat <code>home</code> as your site's landing page and <code>blog</code> as a self-contained, reusable section -- this separation makes it trivial to add a <code>shop</code> or <code>docs</code> app later without touching blog code.</div>\n</section>\n<section class=\"step\" id=\"s6\">\n<div class=\"step-header\">\n<div class=\"step-badge\">06</div>\n<h2>First migrate and superuser</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail ships its own admin, image, document, and search models -- the initial migration creates tables for all of them, not just yours. The superuser logs into <strong>both</strong> the Wagtail admin and Django admin.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py migrate\npython manage.py createsuperuser\npython manage.py runserver</pre>\n</div>\n<div>Visit <code>localhost:8000/admin/</code> for the Wagtail admin (the one editors use daily) and <code>localhost:8000/django-admin/</code> for the raw Django admin (rarely needed once your models are registered with Wagtail panels).</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Add <code>INSTALLED_APPS</code> in <code>blog</code> to <code>core/settings/base.py</code> now if it wasn't auto-added -- run <code>python manage.py startapp</code> doesn't register the app for you.</div>\n</section>\n<section class=\"step\" id=\"s7\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">07</div>\n<h2>Understand the page tree</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>This is the single biggest mental shift from plain Django: every piece of content is a <strong>Page</strong> living in a hierarchical tree, not a flat database row. URLs, permissions, and navigation all derive from tree position automatically.</div>\n<div class=\"step-body\">\n<p>Wagtail's tree starts at an invisible <strong>Root</strong>, under which sits your <strong>Home</strong> page (created by the project template). Your blog will live as two new page types:</p>\n<ul>\n<li><code>BlogIndexPage</code> -- one instance, the <code>/blog/</code> listing page, child of Home</li>\n<li><code>BlogPostPage</code> -- many instances, each a single article, child of BlogIndexPage</li>\n</ul>\n<p>Because URLs are derived from tree position, a post automatically resolves to <code>/blog/my-first-post/</code> with zero manual <code>urls.py</code> routing.</p>\n</div>\n<div>Every page model inherits from <code>wagtail.models.Page</code>, which itself inherits from Django's <code>Model</code> -- so everything you know about Django fields, querysets, and migrations still applies.</div>\n</section>\n<section class=\"step\" id=\"s8\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">08</div>\n<h2>Build the blog index page</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The index page is both a content page (it can have an intro paragraph) and a listing view (it queries its own children). Overriding <code>get_context</code> is how you inject that queryset into the template.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/models.py</span>\n</div>\n<pre><span>from</span> django.db <span>import</span> models\n<span>from</span> wagtail.models <span>import</span> Page\n<span>from</span> wagtail.fields <span>import</span> RichTextField\n<span>from</span> wagtail.admin.panels <span>import</span> FieldPanel\n\n\n<span>class</span> <span>BlogIndexPage</span>(Page):\n intro = RichTextField(blank=<span>True</span>)\n\n content_panels = Page.content_panels + [\n FieldPanel(<span>\"intro\"</span>),\n ]\n\n <span>subpage_types</span> = [<span>\"blog.BlogPostPage\"</span>] <span># only posts can nest here</span>\n <span>max_count</span> = <span>1</span> <span># one blog index for the whole site</span>\n\n <span>def</span> <span>get_context</span>(self, request):\n context = <span>super</span>().<span>get_context</span>(request)\n posts = <span>BlogPostPage</span>.objects.child_of(self).live().<span>order_by</span>(<span>\"-first_published_at\"</span>)\n context[<span>\"posts\"</span>] = posts\n <span>return</span> context</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> <code>.live()</code> filters out drafts automatically -- it's the Wagtail equivalent of <code>status=\"pub\"</code> filtering you'd hand-roll in plain Django.</div>\n</section>\n<section class=\"step\" id=\"s9\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">09</div>\n<h2>Build the blog post page with StreamField</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>StreamField is Wagtail's flagship feature: instead of one big rich-text blob, content is a sequence of typed, structured blocks (heading, paragraph, image, quote, code) that editors can reorder freely. It's what makes Wagtail content artistically flexible instead of a single wall of HTML.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/models.py (continued)</span>\n</div>\n<pre><span>from</span> wagtail.fields <span>import</span> StreamField\n<span>from</span> wagtail.blocks <span>import</span> RichTextBlock, CharBlock, BlockQuoteBlock, ChoiceBlock\n<span>from</span> wagtail.images.blocks <span>import</span> ImageChooserBlock\n<span>from</span> wagtail.search <span>import</span> index\n<span>from</span> modelcluster.fields <span>import</span> ParentalKey, ParentalManyToManyField\n<span>from</span> taggit.models <span>import</span> TaggedItemBase\n\n\n<span>class</span> <span>CodeBlock</span>(<span>ChoiceBlock</span>):\n choices = [(<span>\"python\"</span>, <span>\"Python\"</span>), (<span>\"bash\"</span>, <span>\"Bash\"</span>), (<span>\"html\"</span>, <span>\"HTML\"</span>)]\n\n\n<span>class</span> <span>BlogPostPage</span>(Page):\n date = models.<span>DateField</span>(<span>\"Post date\"</span>)\n excerpt = models.<span>CharField</span>(max_length=<span>280</span>, blank=<span>True</span>)\n cover_image = models.<span>ForeignKey</span>(\n <span>\"wagtailimages.Image\"</span>, null=<span>True</span>, blank=<span>True</span>,\n on_delete=models.SET_NULL, related_name=<span>\"+\"</span>,\n )\n body = <span>StreamField</span>([\n (<span>\"heading\"</span>, CharBlock(form_classname=<span>\"title\"</span>, icon=<span>\"title\"</span>)),\n (<span>\"paragraph\"</span>, RichTextBlock(icon=<span>\"pilcrow\"</span>)),\n (<span>\"image\"</span>, ImageChooserBlock(icon=<span>\"image\"</span>)),\n (<span>\"quote\"</span>, BlockQuoteBlock(icon=<span>\"openquote\"</span>)),\n ], use_json_field=<span>True</span>, blank=<span>True</span>)\n\n tags = <span>ParentalManyToManyField</span>(<span>\"blog.BlogTag\"</span>, blank=<span>True</span>)\n\n <span>search_fields</span> = Page.search_fields + [\n index.SearchField(<span>\"excerpt\"</span>),\n index.SearchField(<span>\"body\"</span>),\n ]\n\n content_panels = Page.content_panels + [\n FieldPanel(<span>\"date\"</span>),\n FieldPanel(<span>\"excerpt\"</span>),\n FieldPanel(<span>\"cover_image\"</span>),\n FieldPanel(<span>\"tags\"</span>),\n FieldPanel(<span>\"body\"</span>),\n ]\n\n <span>parent_page_types</span> = [<span>\"blog.BlogIndexPage\"</span>]\n <span>subpage_types</span> = [] <span># posts can't have child pages</span></pre>\n</div>\n<div class=\"tone-danger\"><strong>Note:</strong> <code>use_json_field=True</code> is required on Wagtail 3+ and stores StreamField content as native JSON rather than serialized XML -- always set it on new fields.</div>\n</section>\n<section class=\"step\" id=\"s10\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">10</div>\n<h2>Tags via django-taggit</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail bundles <code>django-taggit</code> for free-form tagging. A custom tag model (rather than the generic one) lets you filter posts by tag with a clean, dedicated URL.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/models.py (tag model)</span>\n</div>\n<pre><span>class</span> <span>BlogPageTag</span>(<span>TaggedItemBase</span>):\n content_object = <span>ParentalKey</span>(\n <span>\"BlogPostPage\"</span>, related_name=<span>\"tagged_items\"</span>, on_delete=models.CASCADE\n )\n\n\n<span>class</span> <span>BlogTag</span>(models.Model):\n name = models.<span>CharField</span>(max_length=<span>50</span>, unique=<span>True</span>)\n slug = models.<span>SlugField</span>(unique=<span>True</span>)\n\n <span>def</span> <span>__str__</span>(self):\n <span>return</span> self.name</pre>\n</div>\n<div>Add <code>\"taggit\"</code> to <code>INSTALLED_APPS</code> in <code>core/settings/base.py</code> -- it ships with Wagtail but isn't auto-registered for custom tag models.</div>\n</section>\n<section class=\"step\" id=\"s11\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">11</div>\n<h2>Images and renditions</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail's image system generates resized, cropped \"renditions\" on demand and caches them -- you never hand-roll a thumbnail pipeline. The <code>{% image %}</code> template tag is how you request a specific rendition.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">used inside templates (preview)</span>\n</div>\n<pre>{% load wagtailimages_tags %}\n\n{% image page.cover_image fill-800x450 format-webp as cover %}\n<span>&lt;img</span> src=<span>\"{{ cover.url }}\"</span> width=<span>\"{{ cover.width }}\"</span> height=<span>\"{{ cover.height }}\"</span> alt=<span>\"{{ page.cover_image.title }}\"</span><span>&gt;</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> <code>fill-800x450</code> crops to an exact aspect ratio (great for uniform card grids); <code>width-800</code> scales proportionally instead. Append <code>format-webp</code> for smaller file sizes with automatic fallback.</div>\n</section>\n<section class=\"step\" id=\"s12\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">12</div>\n<h2>Run migrations</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Page models migrate exactly like normal Django models -- Wagtail just adds extra tree-management columns (path, depth, numchild) under the hood automatically.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py makemigrations blog\npython manage.py migrate</pre>\n</div>\n<div>In the Wagtail admin, go to <strong>Pages \u2192 Home</strong> and use <strong>\u201cAdd child page\u201d</strong> to create your <code>BlogIndexPage</code> -- new page types only appear in that menu after migrations run.</div>\n</section>\n<section class=\"step\" id=\"s13\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">13</div>\n<h2>Static files and the design direction</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail uses Django's normal static file system. We're building a single hand-crafted stylesheet rather than pulling in a CSS framework, so the blog has a distinct visual identity instead of looking like every other Bootstrap site.</div>\n<div class=\"step-body\">\n<p>Design direction for this build: a dark, <strong>neon-noir / gaming-HUD</strong> aesthetic -- deep ink background, electric magenta and cyan accents, glowing borders, a bold display font for headings, and a monospace font for metadata, mirroring the energy of a game launcher or stream overlay rather than a corporate blog.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/base.py</span>\n</div>\n<pre>STATIC_URL = <span>\"/static/\"</span>\nSTATIC_ROOT = BASE_DIR / <span>\"staticfiles\"</span> <span># collectstatic target</span>\nSTATICFILES_DIRS = [BASE_DIR / <span>\"static\"</span>] <span># your source files</span>\n\nMEDIA_URL = <span>\"/media/\"</span>\nMEDIA_ROOT = BASE_DIR / <span>\"media\"</span></pre>\n</div>\n<div class=\"tree\">\n<span>static/</span>\n \u251c\u2500\u2500 <span>css/</span>\n \u2502 \u2514\u2500\u2500 <span>theme.css</span> <span># the full stylesheet, step 14</span>\n \u2514\u2500\u2500 <span>js/</span>\n \u2514\u2500\u2500 <span>main.js</span> <span># interactions, step 18</span>\n</div>\n<div>Run <code>python manage.py collectstatic</code> only in production builds -- in dev, <code>runserver</code> serves straight from <code>STATICFILES_DIRS</code> automatically.</div>\n</section>\n<section class=\"step\" id=\"s14\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">14</div>\n<h2>The stylesheet: theme.css</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>One global stylesheet, loaded once in the base template, keeps every page visually consistent. CSS custom properties at the top mean you can reskin the entire site by changing a handful of values.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/theme.css</span>\n</div>\n<pre>/* ============================================\n NEBULA -- Wagtail blog theme\n Neon-noir, gaming-HUD inspired\n ============================================ */\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n:root {\n --bg: #08070f;\n --surface: #100e1c;\n --card: #15132a;\n --border: #2a2747;\n --border-bright: #423d70;\n --text: #ece9f7;\n --text-dim: #b6b2d4;\n --muted: #837fa6;\n --accent: #ff2d78; <span>/* magenta */</span>\n --accent-glow: rgba(255,45,120,.35);\n --accent2: #00f0ff; <span>/* cyan */</span>\n --accent2-glow: rgba(0,240,255,.3);\n --accent3: #a742ff; <span>/* violet */</span>\n --gold: #ffc94a;\n --radius: 14px;\n --display: 'Space Grotesk', sans-serif;\n --mono: 'JetBrains Mono', monospace;\n --sans: 'Inter', sans-serif;\n}\n\nhtml { scroll-behavior: smooth; }\n\nbody {\n background:\n radial-gradient(ellipse 900px 600px at 10% -10%, rgba(255,45,120,.10), transparent 60%),\n radial-gradient(ellipse 800px 500px at 100% 0%, rgba(0,240,255,.08), transparent 55%),\n var(--bg);\n color: var(--text);\n font-family: var(--sans);\n line-height: 1.7;\n}\n\na { color: inherit; text-decoration: none; }\n\n/* ===== NAVBAR ===== */\n.site-nav {\n position: sticky; top: 0; z-index: 50;\n display: flex; align-items: center; justify-content: space-between;\n padding: 18px 48px;\n background: rgba(8,7,15,.75);\n backdrop-filter: blur(14px);\n border-bottom: 1px solid var(--border);\n}\n.site-nav .logo {\n font-family: var(--display); font-weight: 700; font-size: 1.2rem;\n display: flex; align-items: center; gap: 8px;\n}\n.site-nav .logo .dot {\n width: 9px; height: 9px; border-radius: 50%;\n background: var(--accent); box-shadow: 0 0 12px var(--accent-glow);\n}\n.site-nav .links { display: flex; gap: 32px; }\n.site-nav .links a {\n font-family: var(--mono); font-size: 13px; color: var(--text-dim);\n letter-spacing: .03em; transition: color .2s;\n}\n.site-nav .links a:hover { color: var(--accent2); }\n\n/* ===== HERO / PAGE HEADER ===== */\n.page-hero {\n position: relative; overflow: hidden;\n padding: 96px 48px 72px;\n border-bottom: 1px solid var(--border);\n}\n.page-hero::before {\n content: ''; position: absolute; top: -200px; left: 20%;\n width: 600px; height: 600px;\n background: radial-gradient(circle, var(--accent-glow), transparent 65%);\n pointer-events: none;\n}\n.page-hero h1 {\n font-family: var(--display); font-weight: 700;\n font-size: clamp(2.4rem, 5vw, 4rem); line-height: 1.05; letter-spacing: -.02em;\n position: relative; z-index: 1;\n}\n.page-hero .accent-text {\n background: linear-gradient(90deg, var(--accent), var(--accent3) 60%, var(--accent2));\n -webkit-background-clip: text; background-clip: text; color: transparent;\n}\n.page-hero p { color: var(--text-dim); max-width: 560px; margin-top: 16px; font-size: 17px; position: relative; z-index: 1; }\n\n/* ===== POST GRID ===== */\n.post-grid {\n display: grid; grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));\n gap: 28px; padding: 56px 48px 100px; max-width: 1280px; margin: 0 auto;\n}\n.post-card {\n background: var(--card); border: 1px solid var(--border); border-radius: var(--radius);\n overflow: hidden; display: flex; flex-direction: column;\n transition: transform .25s ease, border-color .25s ease, box-shadow .25s ease;\n}\n.post-card:hover {\n transform: translateY(-6px);\n border-color: var(--border-bright);\n box-shadow: 0 20px 50px -20px var(--accent-glow);\n}\n.post-card .thumb { aspect-ratio: 16/9; overflow: hidden; background: var(--surface); position: relative; }\n.post-card .thumb img { width: 100%; height: 100%; object-fit: cover; transition: transform .4s ease; }\n.post-card:hover .thumb img { transform: scale(1.06); }\n.post-card .thumb::after {\n content: ''; position: absolute; inset: 0;\n background: linear-gradient(180deg, transparent 60%, rgba(8,7,15,.7));\n}\n.post-card .body { padding: 22px 22px 26px; display: flex; flex-direction: column; gap: 10px; flex: 1; }\n.post-card .tagrow { display: flex; gap: 8px; flex-wrap: wrap; }\n.post-card .tagrow span {\n font-family: var(--mono); font-size: 10px; letter-spacing: .06em; text-transform: uppercase;\n color: var(--accent2); border: 1px solid rgba(0,240,255,.3); border-radius: 20px; padding: 3px 10px;\n}\n.post-card h2 { font-family: var(--display); font-size: 1.2rem; font-weight: 600; line-height: 1.3; }\n.post-card h2 a:hover { color: var(--accent); }\n.post-card p.excerpt { color: var(--muted); font-size: 14px; flex: 1; }\n.post-card .meta {\n display: flex; align-items: center; gap: 10px;\n font-family: var(--mono); font-size: 11px; color: var(--muted);\n padding-top: 10px; border-top: 1px solid var(--border);\n}\n\n/* ===== SINGLE POST ===== */\n.post-cover { width: 100%; max-height: 480px; object-fit: cover; }\n.post-article { max-width: 760px; margin: -60px auto 0; padding: 0 24px 100px; position: relative; z-index: 2; }\n.post-article .card-wrap {\n background: var(--card); border: 1px solid var(--border); border-radius: var(--radius);\n padding: 48px 52px;\n}\n.post-article .eyebrow {\n font-family: var(--mono); font-size: 12px; color: var(--accent2);\n letter-spacing: .08em; text-transform: uppercase; margin-bottom: 14px;\n display: flex; align-items: center; gap: 16px;\n}\n.post-article h1 {\n font-family: var(--display); font-size: clamp(2rem, 4vw, 2.7rem);\n font-weight: 700; line-height: 1.15; margin-bottom: 18px;\n}\n.post-body h2 { font-family: var(--display); font-size: 1.5rem; margin: 36px 0 14px; color: var(--text); }\n.post-body p { color: var(--text-dim); margin-bottom: 16px; font-size: 16px; }\n.post-body img { width: 100%; border-radius: var(--radius); margin: 24px 0; border: 1px solid var(--border); }\n.post-body blockquote {\n border-left: 3px solid var(--accent); background: rgba(255,45,120,.06);\n padding: 16px 22px; margin: 24px 0; border-radius: 0 var(--radius) var(--radius) 0;\n font-style: italic; color: var(--text);\n}\n.tag-pill {\n display: inline-flex; font-family: var(--mono); font-size: 11px; color: var(--accent2);\n border: 1px solid rgba(0,240,255,.3); border-radius: 20px; padding: 4px 12px; margin: 4px 6px 0 0;\n}\n\n/* ===== FOOTER ===== */\n.site-footer {\n border-top: 1px solid var(--border); padding: 40px 48px;\n display: flex; justify-content: space-between; align-items: center;\n font-family: var(--mono); font-size: 12px; color: var(--muted);\n}\n\n@media (max-width: 720px) {\n .site-nav, .page-hero, .post-grid { padding-left: 20px; padding-right: 20px; }\n .post-article { margin-top: -30px; padding: 0 12px 80px; }\n .post-article .card-wrap { padding: 30px 22px; }\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Copy this stylesheet into <code>static/css/theme.css</code> exactly as written -- every selector here is referenced by class names used in the templates in the following steps, so renaming anything here means updating it everywhere else too.</div>\n</section>\n<section class=\"step\" id=\"s15\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">15</div>\n<h2>The base template</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Every Wagtail template extends one base layout, the same way Django templates do. This is also where <code>{% wagtailuserbar %}</code> goes -- it renders the floating edit toolbar for logged-in editors, visible only to them.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/base.html</span>\n</div>\n<pre>{% load static wagtailcore_tags wagtailuserbar %}\n<span>&lt;!DOCTYPE html&gt;</span>\n<span>&lt;html</span> lang=<span>\"en\"</span><span>&gt;</span>\n<span>&lt;head&gt;</span>\n <span>&lt;meta</span> charset=<span>\"utf-8\"</span><span>&gt;</span>\n <span>&lt;meta</span> name=<span>\"viewport\"</span> content=<span>\"width=device-width, initial-scale=1\"</span><span>&gt;</span>\n <span>&lt;title&gt;</span>{% block title %}{{ page.title }}{% endblock %} \u2014 Nebula<span>&lt;/title&gt;</span>\n <span>&lt;link</span> rel=<span>\"preconnect\"</span> href=<span>\"https://fonts.googleapis.com\"</span><span>&gt;</span>\n <span>&lt;link</span> href=<span>\"https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&amp;family=Space+Grotesk:wght@400;500;600;700&amp;family=Inter:wght@400;500;600&amp;display=swap\"</span> rel=<span>\"stylesheet\"</span><span>&gt;</span>\n <span>&lt;link</span> rel=<span>\"stylesheet\"</span> href=<span>\"{% static 'css/theme.css' %}\"</span><span>&gt;</span>\n {% block extra_head %}{% endblock %}\n<span>&lt;/head&gt;</span>\n<span>&lt;body&gt;</span>\n {% wagtailuserbar %}\n\n <span>&lt;nav</span> class=<span>\"site-nav\"</span><span>&gt;</span>\n <span>&lt;a</span> class=<span>\"logo\"</span> href=<span>\"/\"</span><span>&gt;</span><span>&lt;span</span> class=<span>\"dot\"</span><span>&gt;&lt;/span&gt;</span>NEBULA<span>&lt;/a&gt;</span>\n <span>&lt;div</span> class=<span>\"links\"</span><span>&gt;</span>\n <span>&lt;a</span> href=<span>\"/blog/\"</span><span>&gt;</span>Blog<span>&lt;/a&gt;</span>\n <span>&lt;a</span> href=<span>\"/search/\"</span><span>&gt;</span>Search<span>&lt;/a&gt;</span>\n <span>&lt;/div&gt;</span>\n <span>&lt;/nav&gt;</span>\n\n <span>&lt;main&gt;</span>\n {% block content %}{% endblock %}\n <span>&lt;/main&gt;</span>\n\n <span>&lt;footer</span> class=<span>\"site-footer\"</span><span>&gt;</span>\n <span>&lt;span&gt;</span>\u00a9 {% now \"Y\" %} Nebula Blog<span>&lt;/span&gt;</span>\n <span>&lt;span&gt;</span>Built with Wagtail<span>&lt;/span&gt;</span>\n <span>&lt;/footer&gt;</span>\n\n <span>&lt;script</span> src=<span>\"{% static 'js/main.js' %}\"</span> defer<span>&gt;&lt;/script&gt;</span>\n {% block extra_js %}{% endblock %}\n<span>&lt;/body&gt;</span>\n<span>&lt;/html&gt;</span></pre>\n</div>\n<div><code>{% wagtailuserbar %}</code> renders nothing for anonymous visitors -- it's safe to leave in production templates permanently.</div>\n</section>\n<section class=\"step\" id=\"s16\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">16</div>\n<h2>Blog index template (the grid)</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail auto-resolves a template path from the model name: <code>BlogIndexPage</code> \u2192 <code>blog/blog_index_page.html</code>. No manual view-to-template wiring required.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">blog/templates/blog/blog_index_page.html</span>\n</div>\n<pre>{% extends \"base.html\" %}\n{% load wagtailcore_tags wagtailimages_tags %}\n\n{% block content %}\n<span>&lt;header</span> class=<span>\"page-hero\"</span><span>&gt;</span>\n <span>&lt;h1&gt;</span>The <span>&lt;span</span> class=<span>\"accent-text\"</span><span>&gt;</span>Nebula<span>&lt;/span&gt;</span> Blog<span>&lt;/h1&gt;</span>\n <span>&lt;p&gt;</span>{{ page.intro|richtext }}<span>&lt;/p&gt;</span>\n<span>&lt;/header&gt;</span>\n\n<span>&lt;div</span> class=<span>\"post-grid\"</span><span>&gt;</span>\n {% for post in posts %}\n <span>&lt;article</span> class=<span>\"post-card\"</span><span>&gt;</span>\n <span>&lt;div</span> class=<span>\"thumb\"</span><span>&gt;</span>\n {% if post.cover_image %}\n {% image post.cover_image fill-640x360 format-webp as thumb %}\n <span>&lt;img</span> src=<span>\"{{ thumb.url }}\"</span> alt=<span>\"{{ post.title }}\"</span><span>&gt;</span>\n {% endif %}\n <span>&lt;/div&gt;</span>\n <span>&lt;div</span> class=<span>\"body\"</span><span>&gt;</span>\n <span>&lt;div</span> class=<span>\"tagrow\"</span><span>&gt;</span>\n {% for tag in post.tags.all %}<span>&lt;span&gt;</span>{{ tag.name }}<span>&lt;/span&gt;</span>{% endfor %}\n <span>&lt;/div&gt;</span>\n <span>&lt;h2&gt;&lt;a</span> href=<span>\"{% pageurl post %}\"</span><span>&gt;</span>{{ post.title }}<span>&lt;/a&gt;&lt;/h2&gt;</span>\n <span>&lt;p</span> class=<span>\"excerpt\"</span><span>&gt;</span>{{ post.excerpt }}<span>&lt;/p&gt;</span>\n <span>&lt;div</span> class=<span>\"meta\"</span><span>&gt;</span>\n <span>&lt;span&gt;</span>{{ post.date|date:\"M j, Y\" }}<span>&lt;/span&gt;</span>\n <span>&lt;/div&gt;</span>\n <span>&lt;/div&gt;</span>\n <span>&lt;/article&gt;</span>\n {% empty %}\n <span>&lt;p&gt;</span>No posts published yet.<span>&lt;/p&gt;</span>\n {% endfor %}\n<span>&lt;/div&gt;</span>\n{% endblock %}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Always use <code>{% pageurl post %}</code>, never hardcode <code>/blog/{{ post.slug }}/</code> -- it correctly handles pages that get moved in the tree later.</div>\n</section>\n<section class=\"step\" id=\"s17\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">17</div>\n<h2>Blog post template + StreamField rendering</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The <code>{% include_block %}</code> tag walks the StreamField and renders each block using Wagtail's built-in block templates, or your own overrides for full art-direction control.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">blog/templates/blog/blog_post_page.html</span>\n</div>\n<pre>{% extends \"base.html\" %}\n{% load wagtailcore_tags wagtailimages_tags %}\n\n{% block content %}\n{% if page.cover_image %}\n {% image page.cover_image fill-1600x500 format-webp as cover %}\n <span>&lt;img</span> class=<span>\"post-cover\"</span> src=<span>\"{{ cover.url }}\"</span> alt=<span>\"{{ page.title }}\"</span><span>&gt;</span>\n{% endif %}\n\n<span>&lt;article</span> class=<span>\"post-article\"</span><span>&gt;</span>\n <span>&lt;div</span> class=<span>\"card-wrap\"</span><span>&gt;</span>\n <span>&lt;p</span> class=<span>\"eyebrow\"</span><span>&gt;</span>\n <span>&lt;span&gt;</span>{{ page.date|date:\"F j, Y\" }}<span>&lt;/span&gt;</span>\n <span>&lt;/p&gt;</span>\n <span>&lt;h1&gt;</span>{{ page.title }}<span>&lt;/h1&gt;</span>\n\n <span>&lt;div</span> class=<span>\"post-body\"</span><span>&gt;</span>\n {% for block in page.body %}\n {% include_block block %}\n {% endfor %}\n <span>&lt;/div&gt;</span>\n\n <span>&lt;div</span> style=<span>\"margin-top:32px\"</span><span>&gt;</span>\n {% for tag in page.tags.all %}\n <span>&lt;span</span> class=<span>\"tag-pill\"</span><span>&gt;</span>#{{ tag.name }}<span>&lt;/span&gt;</span>\n {% endfor %}\n <span>&lt;/div&gt;</span>\n <span>&lt;/div&gt;</span>\n<span>&lt;/article&gt;</span>\n{% endblock %}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">blog/templates/blocks/quote_block.html (custom override)</span>\n</div>\n<pre>{% load wagtailcore_tags %}\n<span>&lt;blockquote&gt;</span>\u201c{{ value }}\u201d<span>&lt;/blockquote&gt;</span></pre>\n</div>\n<div>To use a custom block template, register it on the block definition: <code>BlockQuoteBlock(template=\"blocks/quote_block.html\")</code> back in <code>models.py</code>. Without an explicit template, Wagtail falls back to its sensible defaults for built-in block types.</div>\n</section>\n<section class=\"step\" id=\"s18\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">18</div>\n<h2>JS interactions: main.js</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The design only needs light JS: a scroll-aware navbar state and a subtle reveal-on-scroll for post cards -- enough motion to feel alive without fighting the CMS-rendered HTML.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">JavaScript</span>\n<span class=\"code-file\">static/js/main.js</span>\n</div>\n<pre><span>// Reveal post cards as they scroll into view</span>\n<span>const</span> cards = document.<span>querySelectorAll</span>(<span>'.post-card'</span>);\n<span>if</span> (cards.length) {\n cards.<span>forEach</span>(c =&gt; { c.style.opacity = <span>'0'</span>; c.style.transform = <span>'translateY(18px)'</span>; });\n <span>const</span> io = <span>new</span> <span>IntersectionObserver</span>((entries) =&gt; {\n entries.<span>forEach</span>(e =&gt; {\n <span>if</span> (e.isIntersecting) {\n e.target.style.transition = <span>'opacity .5s ease, transform .5s ease'</span>;\n e.target.style.opacity = <span>'1'</span>;\n e.target.style.transform = <span>'translateY(0)'</span>;\n io.<span>unobserve</span>(e.target);\n }\n });\n }, { threshold: <span>0.15</span> });\n cards.<span>forEach</span>(c =&gt; io.<span>observe</span>(c));\n}\n\n<span>// Sticky nav background intensifies after scrolling</span>\n<span>const</span> nav = document.<span>querySelector</span>(<span>'.site-nav'</span>);\n<span>if</span> (nav) {\n window.<span>addEventListener</span>(<span>'scroll'</span>, () =&gt; {\n nav.style.borderBottomColor = window.scrollY &gt; 40 ? <span>'var(--border-bright)'</span> : <span>'var(--border)'</span>;\n });\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Keep JS strictly progressive-enhancement -- if it fails to load, the page must still be fully readable. Nothing here gates content visibility.</div>\n</section>\n<section class=\"step\" id=\"s19\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">19</div>\n<h2>Create 3 starter posts</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A blog with zero content can't be evaluated visually. These three posts exercise every StreamField block type (heading, paragraph, image, quote) so you can confirm the design renders correctly before writing real content.</div>\n<div class=\"step-body\">\n<p>In the Wagtail admin, open <strong>Pages \u2192 Home \u2192 The Nebula Blog</strong>, click <strong>\u201cAdd child page\u201d</strong>, and create each post below. Set <strong>Date</strong> to today (or stagger them), fill <strong>Excerpt</strong>, upload any <strong>Cover image</strong>, add a couple of <strong>Tags</strong>, then build the body using the block picker.</p>\n</div>\n<div class=\"tbl-wrap\">\n<table>\n<tr><th>Field</th><th>Post 1</th><th>Post 2</th><th>Post 3</th></tr>\n<tr>\n<td>Title</td>\n<td>Designing Interfaces That Feel Like a HUD</td>\n<td>Why StreamField Beats a Single Rich Text Box</td>\n<td>Shipping Wagtail to Production Without Surprises</td>\n</tr>\n<tr>\n<td>Excerpt</td>\n<td>How borrowing visual language from game UIs makes a content site feel alive instead of static.</td>\n<td>A flexible content model is the difference between an editor who's empowered and one who's fighting the CMS.</td>\n<td>The checklist that turns \"works on my machine\" into a deployment you can trust.</td>\n</tr>\n<tr><td>Tags</td><td>design, ui</td><td>wagtail, cms</td><td>deploy, django</td></tr>\n</table>\n</div>\n<div class=\"step-body\">\n<p><strong>Post 1 body</strong> (block sequence):</p>\n<ul>\n<li><strong>Heading:</strong> \u201cBorrow from the cockpit, not the brochure\u201d</li>\n<li><strong>Paragraph:</strong> Most content sites default to a neutral, brochure-style aesthetic -- white background, blue links, safe sans-serif. A HUD-inspired interface instead treats the screen like a dashboard: glowing accents mark what matters, monospace type signals data and metadata, and dark backgrounds let color do more work with less of it.</li>\n<li><strong>Image:</strong> any wide screenshot or photo you have on hand</li>\n<li><strong>Quote:</strong> \u201cGood interface design doesn't decorate content -- it directs attention.\u201d</li>\n<li><strong>Heading:</strong> \u201cThree rules that hold the look together\u201d</li>\n<li><strong>Paragraph:</strong> Keep glow effects rare and purposeful so they still draw the eye when used. Keep one display font for headings and one monospace for labels -- never more than two typefaces. And let every accent color map to a single meaning across the whole site, so cyan always means \"metadata\" and magenta always means \"primary action.\"</li>\n</ul>\n</div>\n<div class=\"step-body\">\n<p><strong>Post 2 body</strong> (block sequence):</p>\n<ul>\n<li><strong>Heading:</strong> \u201cThe problem with one big text field\u201d</li>\n<li><strong>Paragraph:</strong> A single rich-text field forces every layout decision into inline HTML hacks -- centered images, custom callouts, code samples -- all bolted onto a field that was only ever designed for paragraphs and bold text.</li>\n<li><strong>Quote:</strong> \u201cStreamField turns content into structured data, not a blob of markup.\u201d</li>\n<li><strong>Heading:</strong> \u201cWhat structured blocks unlock\u201d</li>\n<li><strong>Paragraph:</strong> Because each block is typed, you can render a heading block differently from a paragraph block, swap an image block's crop ratio sitewide by editing one template, or add a brand-new block type later without migrating existing content.</li>\n<li><strong>Image:</strong> any diagram or screenshot</li>\n</ul>\n</div>\n<div class=\"step-body\">\n<p><strong>Post 3 body</strong> (block sequence):</p>\n<ul>\n<li><strong>Heading:</strong> \u201cProduction is a checklist, not a vibe\u201d</li>\n<li><strong>Paragraph:</strong> The gap between a working dev server and a production deployment is entirely mechanical: environment variables, a real database, static file collection, and a process manager in front of Django's dev server.</li>\n<li><strong>Quote:</strong> \u201cDEBUG = False is not a setting, it's a mindset.\u201d</li>\n<li><strong>Heading:</strong> \u201cWhat this guide covers next\u201d</li>\n<li><strong>Paragraph:</strong> The remaining steps split settings for environments, switch SQLite for PostgreSQL, configure search, and wire up Gunicorn behind Nginx -- the same pattern that scales from a single blog to a multi-app platform.</li>\n</ul>\n</div>\n<div>Publish all three (don't leave them as drafts) so <code>.live()</code> picks them up on the index page. Refresh <code>/blog/</code> and you should see a 3-card grid render in the neon-noir theme.</div>\n</section>\n<section class=\"step\" id=\"s20\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">20</div>\n<h2>Split settings for production</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail's project template already gives you <code>dev.py</code> and <code>production.py</code> -- you just need to populate the production file with environment-driven secrets instead of hardcoded values.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install python-decouple dj-database-url\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre><span>from</span> decouple <span>import</span> config\n<span>from</span> .base <span>import</span> *\n\nDEBUG = <span>False</span>\nSECRET_KEY = <span>config</span>(<span>\"SECRET_KEY\"</span>)\nALLOWED_HOSTS = <span>config</span>(<span>\"ALLOWED_HOSTS\"</span>, cast=<span>lambda</span> v: v.split(<span>\",\"</span>))\n\nSECURE_SSL_REDIRECT = <span>True</span>\nSESSION_COOKIE_SECURE = <span>True</span>\nCSRF_COOKIE_SECURE = <span>True</span>\nSECURE_HSTS_SECONDS = <span>31536000</span>\nSECURE_CONTENT_TYPE_NOSNIFF = <span>True</span>\nWAGTAILADMIN_BASE_URL = <span>config</span>(<span>\"WAGTAILADMIN_BASE_URL\"</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env (never commit this file)</span>\n</div>\n<pre>SECRET_KEY=your-secret-key-here\nALLOWED_HOSTS=yourdomain.com,www.yourdomain.com\nWAGTAILADMIN_BASE_URL=https://yourdomain.com\nDATABASE_URL=postgres://user:pass@localhost/nebulablog\nDJANGO_SETTINGS_MODULE=core.settings.production</pre>\n</div>\n<div><code>WAGTAILADMIN_BASE_URL</code> is Wagtail-specific -- it's used to build absolute URLs in things like password-reset emails and the page preview panel, so don't skip it.</div>\n</section>\n<section class=\"step\" id=\"s21\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">21</div>\n<h2>PostgreSQL and media storage</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>SQLite can't handle concurrent writes from multiple Gunicorn workers safely. And local-disk media storage doesn't survive redeploys on most PaaS platforms -- uploaded post images need to live in object storage.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install psycopg2-binary django-storages boto3\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py (continued)</span>\n</div>\n<pre><span>import</span> dj_database_url\n\nDATABASES = {\n <span>\"default\"</span>: dj_database_url.<span>config</span>(\n default=<span>config</span>(<span>\"DATABASE_URL\"</span>), conn_max_age=<span>600</span>, ssl_require=<span>True</span>,\n )\n}\n\n<span># media \u2192 S3-compatible bucket (works with AWS S3, Backblaze, DO Spaces)</span>\nDEFAULT_FILE_STORAGE = <span>\"storages.backends.s3boto3.S3Boto3Storage\"</span>\nAWS_STORAGE_BUCKET_NAME = <span>config</span>(<span>\"AWS_STORAGE_BUCKET_NAME\"</span>)\nAWS_ACCESS_KEY_ID = <span>config</span>(<span>\"AWS_ACCESS_KEY_ID\"</span>)\nAWS_SECRET_ACCESS_KEY = <span>config</span>(<span>\"AWS_SECRET_ACCESS_KEY\"</span>)\nAWS_S3_REGION_NAME = <span>config</span>(<span>\"AWS_S3_REGION_NAME\"</span>, default=<span>\"us-east-1\"</span>)\nAWS_DEFAULT_ACL = <span>None</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Wagtail's image renditions are regenerated on demand and cached -- you don't need to pre-generate every size. Just make sure the bucket allows public-read on the media path, or use signed URLs if the blog is private.</div>\n</section>\n<section class=\"step\" id=\"s22\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">22</div>\n<h2>Configure the search backend</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Wagtail's default search backend is database-only and fine for small sites, but slow to scale. Swapping in PostgreSQL's native full-text search is a one-line config change with no extra infrastructure.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre>WAGTAILSEARCH_BACKENDS = {\n <span>\"default\"</span>: {\n <span>\"BACKEND\"</span>: <span>\"wagtail.search.backends.database\"</span>,\n <span>\"SEARCH_CONFIG\"</span>: <span>\"english\"</span>,\n }\n}</pre>\n</div>\n<div>For high-traffic sites, swap this for <code>wagtail.search.backends.elasticsearch7</code> -- but Postgres full-text search comfortably handles most blogs without running a separate search cluster.</div>\n</section>\n<section class=\"step\" id=\"s23\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">23</div>\n<h2>Gunicorn + Nginx</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The Django dev server is single-threaded and not built for public traffic. Gunicorn runs multiple worker processes behind Nginx, which handles TLS termination and serves static files directly without hitting Python.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install gunicorn whitenoise\npip freeze &gt; requirements.txt\n\n<span># collect static assets before starting</span>\nDJANGO_SETTINGS_MODULE=core.settings.production python manage.py collectstatic --noinput\n\n<span># start Gunicorn (4 workers handles ~200 concurrent requests)</span>\ngunicorn core.wsgi:application --workers 4 --bind 0.0.0.0:8000</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">/etc/nginx/sites-available/nebulablog</span>\n</div>\n<pre>server {\n listen 80;\n server_name yourdomain.com;\n\n location /static/ {\n alias /path/to/nebulablog/staticfiles/;\n }\n location /media/ {\n alias /path/to/nebulablog/media/; <span># skip if using S3 storage</span>\n }\n location / {\n proxy_pass http://127.0.0.1:8000;\n proxy_set_header Host $host;\n proxy_set_header X-Real-IP $remote_addr;\n proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n proxy_set_header X-Forwarded-Proto $scheme;\n }\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> On platforms like Railway, Render, or Fly.io, skip Nginx entirely and add <code>whitenoise.middleware.WhiteNoiseMiddleware</code> right after <code>SecurityMiddleware</code> in <code>MIDDLEWARE</code> -- Gunicorn + Whitenoise serves everything on its own.</div>\n</section>\n<section class=\"step\" id=\"s24\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">24</div>\n<h2>Pre-deploy checklist</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's built-in deploy check catches the most common security misconfigurations automatically -- run it as the final gate before every release.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>DJANGO_SETTINGS_MODULE=core.settings.production python manage.py check --deploy\npython manage.py migrate\npython manage.py collectstatic --noinput</pre>\n</div>\n<div>\n Every item to verify before going live:\n <br/>- DEBUG = False in production settings\n <br/>- SECRET_KEY is strong and not in source control\n <br/>- ALLOWED_HOSTS lists only your real domain(s)\n <br/>- HTTPS enforced (SECURE_SSL_REDIRECT = True)\n <br/>- DATABASE_URL points to PostgreSQL, not SQLite\n <br/>- WAGTAILADMIN_BASE_URL set to the live https:// domain\n <br/>- Media storage points to object storage, not local disk\n <br/>- STATIC_ROOT populated via collectstatic\n <br/>- Wagtail admin password is strong; consider 2FA via django-allauth\n <br/>- Error logging configured (Sentry's Wagtail integration is officially supported)\n </div>\n</section>\n<section id=\"cheatsheet\">\n<h2>Wagtail Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference commands, page model APIs, template tags, and StreamField patterns.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span>\u2328</span><h3>Management Commands</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>wagtail start name .</code><span>Scaffold a new Wagtail project</span></div>\n<div class=\"cheat-item\"><code>startapp name</code><span>Create a new Django app (manual, as usual)</span></div>\n<div class=\"cheat-item\"><code>makemigrations</code><span>Generate migrations from page/model changes</span></div>\n<div class=\"cheat-item\"><code>migrate</code><span>Apply pending migrations</span></div>\n<div class=\"cheat-item\"><code>createsuperuser</code><span>Create an admin account for both admins</span></div>\n<div class=\"cheat-item\"><code>update_index</code><span>Rebuild the search index after backend changes</span></div>\n<div class=\"cheat-item\"><code>collectstatic</code><span>Gather static files into STATIC_ROOT</span></div>\n<div class=\"cheat-item\"><code>check --deploy</code><span>Run security checks for production</span></div>\n<div class=\"cheat-item\"><code>fixtree</code><span>Repair a corrupted page tree (rare, but vital)</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Page QuerySet API</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>.live()</code><span>Only published pages (excludes drafts)</span></div>\n<div class=\"cheat-item\"><code>.child_of(page)</code><span>Direct children of a given page</span></div>\n<div class=\"cheat-item\"><code>.descendant_of(page)</code><span>All descendants, any depth</span></div>\n<div class=\"cheat-item\"><code>.sibling_of(page)</code><span>Pages sharing the same parent</span></div>\n<div class=\"cheat-item\"><code>.type(Model)</code><span>Filter by a specific page class</span></div>\n<div class=\"cheat-item\"><code>.in_menu()</code><span>Pages flagged to show in navigation</span></div>\n<div class=\"cheat-item\"><code>.specific()</code><span>Return actual subclasses, not base Page</span></div>\n<div class=\"cheat-item\"><code>.search(query)</code><span>Full-text search via active backend</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Template Tags</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{% pageurl page %}</code><span>Correct URL for any Page instance</span></div>\n<div class=\"cheat-item\"><code>{% slugurl 'slug' %}</code><span>URL lookup by slug instead of object</span></div>\n<div class=\"cheat-item\"><code>{{ value|richtext }}</code><span>Render a RichTextField safely</span></div>\n<div class=\"cheat-item\"><code>{% include_block blk %}</code><span>Render one StreamField block</span></div>\n<div class=\"cheat-item\"><code>{% image im fill-300x300 %}</code><span>Render a cropped image rendition</span></div>\n<div class=\"cheat-item\"><code>{% wagtailuserbar %}</code><span>Floating edit toolbar for logged-in editors</span></div>\n<div class=\"cheat-item\"><code>{% load static %}</code><span>Enable static tag (same as plain Django)</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>StreamField Block Types</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>CharBlock()</code><span>Single-line text input</span></div>\n<div class=\"cheat-item\"><code>RichTextBlock()</code><span>WYSIWYG editor for one section</span></div>\n<div class=\"cheat-item\"><code>ImageChooserBlock()</code><span>Pick an image from the library</span></div>\n<div class=\"cheat-item\"><code>BlockQuoteBlock()</code><span>Styled pull-quote block</span></div>\n<div class=\"cheat-item\"><code>StructBlock([...])</code><span>Group multiple sub-fields as one block</span></div>\n<div class=\"cheat-item\"><code>ListBlock(SubBlock())</code><span>Repeatable list of one block type</span></div>\n<div class=\"cheat-item\"><code>StreamBlock([...])</code><span>Nested stream within a StructBlock</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Security Settings</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>SECURE_SSL_REDIRECT</code><span>Force HTTP to HTTPS in production</span></div>\n<div class=\"cheat-item\"><code>SESSION_COOKIE_SECURE</code><span>Cookies only sent over HTTPS</span></div>\n<div class=\"cheat-item\"><code>WAGTAILADMIN_BASE_URL</code><span>Required for emails and preview links</span></div>\n<div class=\"cheat-item\"><code>WAGTAIL_PASSWORD_*</code><span>Tune password reset / change behavior</span></div>\n<div class=\"cheat-item\"><code>X_FRAME_OPTIONS</code><span>Set \"DENY\" to block clickjacking</span></div>\n<div class=\"cheat-item\"><code>SECURE_HSTS_SECONDS</code><span>HSTS header lifetime, e.g. 31536000</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Performance Tips</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>.specific(defer=True)</code><span>Avoid loading subclass fields you don't need</span></div>\n<div class=\"cheat-item\"><code>select_related()</code><span>Eliminates N+1 on ForeignKey lookups</span></div>\n<div class=\"cheat-item\"><code>prefetch_related()</code><span>Eliminates N+1 on tags / M2M fields</span></div>\n<div class=\"cheat-item\"><code>fill-WxH format-webp</code><span>Smaller, pre-cropped image renditions</span></div>\n<div class=\"cheat-item\"><code>cache_page(60*15)</code><span>Cache a whole view for 15 minutes</span></div>\n<div class=\"cheat-item\"><code>WAGTAIL_CACHE</code><span>Enable Wagtail's page cache backend</span></div>\n</div>\n</div>\n</div>\n</section>";

